UPDATE stock
SET available = available - #{quantity},
    locked = locked + #{quantity},
    version = version + 1
WHERE event_id = #{eventId}
  AND version = #{version}
  AND available >= #{quantity}

UPDATE stock
SET locked = locked - #{quantity},
    sold = sold + #{quantity},
    version = version + 1
WHERE event_id = #{eventId}
  AND locked >= #{quantity}

UPDATE stock
SET locked = locked - #{quantity},
    available = available + #{quantity},
    version = version + 1
WHERE event_id = #{eventId}
  AND locked >= #{quantity}
